import{_ as e,c as i,ag as a,o as r}from"./chunks/framework.mHuDn-wg.js";const _=JSON.parse('{"title":"文件格式和扩展名","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/计算机软硬件/文件.md","filePath":"计算机/计算机软硬件/文件.md","lastUpdated":null}'),t={name:"计算机/计算机软硬件/文件.md"};function o(n,l,c,s,d,u){return r(),i("div",null,l[0]||(l[0]=[a('<h1 id="文件格式和扩展名" tabindex="-1">文件格式和扩展名 <a class="header-anchor" href="#文件格式和扩展名" aria-label="Permalink to &quot;文件格式和扩展名&quot;">​</a></h1><ul><li>根据文件存储的信息类型, 粗略分为两类 <ul><li>纯文本文件: 人类可读的字符数据, 通过文本编辑器查看和编辑</li><li>二进制文件: 需要特定程序或工具解析和处理, 图像,音频,视频,可执行文件等等</li></ul></li><li>扩展名虽然指示文件类型或格式, 并不能决定文件本质的内容和信息. <ul><li>告诉操作系统, 文件的默认打开方式, 关联文件和特定的应用程序</li><li>帮助用户分类和管理文件</li><li>手动更改扩展名并不影响文件内容</li></ul></li><li>软件程序真正识别文件内容的方式: 文件头和文件尾, 而不是扩展名.</li><li>单一功能的软件只能识别特定类型的文件头尾, 对于存储了多类型信息的文件, 有时可以读取其中的部分内容, 例如: <ul><li>用音乐播放器打开视频文件</li><li>用解压缩软件打开PPT</li></ul></li><li><strong>纯文本文件没有文件头尾</strong>, 因此不包含任何格式信息</li></ul><h2 id="文件编码格式" tabindex="-1">文件编码格式 <a class="header-anchor" href="#文件编码格式" aria-label="Permalink to &quot;文件编码格式&quot;">​</a></h2><ul><li>所有文件都是用 0 1 机器码以字节为单位存储, 编码格式决定了字符与字节之间的映射关系</li><li>常见的编码格式: ASCII, UTF-8, UTF-16, GBK</li><li>Macintosh(CR)和Windows(CRLF)</li><li><a href="https://learn.microsoft.com/zh-cn/powershell/scripting/dev-cross-plat/vscode/understanding-file-encoding?view=powershell-7.4" target="_blank" rel="noreferrer">了解 VS Code 和 PowerShell 中的文件编码 - PowerShell | Microsoft Learn</a></li><li><a href="https://cloud.tencent.com/developer/article/2075577" target="_blank" rel="noreferrer">powershell重定向文本文件时注意显性指定编码-腾讯云开发者社区-腾讯云 (tencent.com)</a></li></ul><h3 id="ascii" tabindex="-1">ASCII <a class="header-anchor" href="#ascii" aria-label="Permalink to &quot;ASCII&quot;">​</a></h3><ul><li>ASCII（American Standard Code for Information Interchange，美国信息交换标准代码）是一种较早的字符编码标准</li><li>使用7位二进制数来表示字符，因此最多可以表示128个字符</li><li>包括大写字母、小写字母、数字、标点符号以及一些控制字符</li><li>标准ASCII码使用7位二进制数，在某些系统中扩展到了8位, 可以表示最多256个字符</li></ul><h3 id="unicode" tabindex="-1">Unicode <a class="header-anchor" href="#unicode" aria-label="Permalink to &quot;Unicode&quot;">​</a></h3><ul><li>Unicode, 也称万国码, 是一种更为现代和全面的字符编码标准，旨在支持世界上几乎所有的书写系统和符号</li><li>使用多个字节（通常是2到4个字节）来表示字符，因此可以表示超过一百万个字符 <ul><li>根据使用的二进制位数不同, 提供了多种编码形式, 如UTF-8、UTF-16和UTF-32，以适应不同的存储需求</li><li>其中，UTF-8是一种<em>变长编码</em>，兼容ASCII，并且在处理英文文本时非常高效</li><li><blockquote><p>变长编码是一种编码方式，其特点是每个字符的编码长度不固定，可以根据字符出现的频率来分配不同的编码长度</p></blockquote></li></ul></li><li>不仅包括各种语言的字母、符号、还包括了表情符号</li></ul>',8)]))}const p=e(t,[["render",o]]);export{_ as __pageData,p as default};
